function hasPermission(
    address who_,
    string memory resource_,
    string memory permission_
) public view virtual override returns (bool isAllowed_) {
    string[] memory roles_ = getUserRoles(who_);

    for (uint256 i = 0; i < roles_.length; ++i) {
        string memory role_ = roles_[i];

        if (_isDisallowed(role_, resource_, permission_)) {
            return false;
        }

        isAllowed_ = isAllowed_ || _isAllowed(role_, resource_, permission_);
    }

    string[] memory groups_ = getUserGroups(who_);

    for (uint256 i = 0; i < groups_.length; ++i) {
        roles_ = getGroupRoles(groups_[i]);

        for (uint256 j = 0; j < roles_.length; ++j) {
            string memory role_ = roles_[j];

            if (_isDisallowed(role_, resource_, permission_)) {
                return false;
            }

            isAllowed_ = isAllowed_ || _isAllowed(role_, resource_, permission_);
        }
    }
}

function parseBlockHeader(
    bytes calldata blockHeaderRaw_,
    bool returnInBEFormat_
) internal pure returns (HeaderData memory headerData_, bytes32 blockHash_) {
    if (blockHeaderRaw_.length != BLOCK_HEADER_DATA_LENGTH)
        revert InvalidBlockHeaderDataLength();

    headerData_ = HeaderData({
        version: uint32(bytes4(blockHeaderRaw_[0:4])),
        prevBlockHash: bytes32(blockHeaderRaw_[4:36]),
        merkleRoot: bytes32(blockHeaderRaw_[36:68]),
        time: uint32(bytes4(blockHeaderRaw_[68:72])),
        bits: bytes4(blockHeaderRaw_[72:76]),
        nonce: uint32(bytes4(blockHeaderRaw_[76:80]))
    });

    blockHash_ = _getBlockHeaderHash(blockHeaderRaw_);

    if (returnInBEFormat_) {
        headerData_.version = headerData_.version.uint32LEtoBE();
        headerData_.prevBlockHash = headerData_.prevBlockHash.bytes32LEtoBE();
        headerData_.merkleRoot = headerData_.merkleRoot.bytes32LEtoBE();
        headerData_.time = headerData_.time.uint32LEtoBE();
        headerData_.bits = bytes4(uint32(headerData_.bits).uint32LEtoBE());
        headerData_.nonce = headerData_.nonce.uint32LEtoBE();

        blockHash_ = blockHash_.bytes32LEtoBE();
    }
}

function _parseTransactionInput(
    bytes calldata data_,
    uint256 offset_
) private pure returns (TransactionInput memory input_, uint256 consumed_) {
    uint256 position_ = offset_;

    _checkForBufferOverflow(position_ + 32, data_.length);

    input_.previousHash = (bytes32(data_.slice(position_, position_ + 32))).bytes32LEtoBE();

    position_ += 32;

    _checkForBufferOverflow(position_ + 4, data_.length);

    input_.previousIndex = uint32(bytes4(data_[position_:position_ + 4])).uint32LEtoBE();

    position_ += 4;

    uint256 scriptLen_;
    uint256 lenSize_;

    (scriptLen_, lenSize_) = _parseCuint(data_, position_);

    position_ += lenSize_;

    _checkForBufferOverflow(position_ + scriptLen_, data_.length);

    input_.script = data_.slice(position_, position_ + scriptLen_);

    position_ += scriptLen_;

    _checkForBufferOverflow(position_ + 4, data_.length);

    input_.sequence = uint32(bytes4(data_[position_:position_ + 4])).uint32LEtoBE();

    position_ += 4;

    consumed_ = position_ - offset_;
}

function _twiceAffine(
    call512 call_,
    uint512 p_,
    uint512 two_,
    uint512 three_,
    uint512 a_,
    uint512 x1_,
    uint512 y1_
) private view returns (uint512 x2_, uint512 y2_) {
    unchecked {
        if (U512.isNull(x1_)) {
            return (x2_, y2_);
        }

        if (U512.eqU256(y1_, 0)) {
            return (x2_, y2_);
        }

        uint512 m1_ = U512.modexpU256(call_, x1_, 2, p_);
        U512.modmulAssign(call_, m1_, three_, p_);
        U512.redaddAssign(call_, m1_, a_, p_);

        uint512 m2_ = U512.modmul(call_, y1_, two_, p_);
        U512.moddivAssign(call_, m1_, m2_, p_);

        x2_ = U512.modexpU256(call_, m1_, 2, p_);
        U512.redsubAssign(call_, x2_, x1_, p_);
        U512.redsubAssign(call_, x2_, x1_, p_);

        y2_ = U512.redsub(call_, x1_, x2_, p_);
        U512.modmulAssign(call_, y2_, m1_, p_);
        U512.redsubAssign(call_, y2_, y1_, p_);
    }
}

function _pAdd(
    PPoint memory pPoint1_,
    PPoint memory pPoint2_,
    uint256 p_,
    uint256 a_,
    uint256 d_
) private pure returns (PPoint memory pPoint3_) {
    assembly ("memory-safe") {
        let A_ := mulmod(mload(add(pPoint1_, 0x40)), mload(add(pPoint2_, 0x40)), p_)
        let B_ := mulmod(A_, A_, p_)
        let C_ := mulmod(mload(pPoint1_), mload(pPoint2_), p_)
        let D_ := mulmod(mload(add(pPoint1_, 0x20)), mload(add(pPoint2_, 0x20)), p_)
        let E_ := mulmod(d_, mulmod(C_, D_, p_), p_)
        let F_ := addmod(B_, sub(p_, E_), p_)
        B_ := addmod(B_, E_, p_)
        let H_ := mulmod(
            addmod(mload(pPoint1_), mload(add(pPoint1_, 0x20)), p_),
            addmod(mload(pPoint2_), mload(add(pPoint2_, 0x20)), p_),
            p_
        )
        H_ := addmod(addmod(H_, sub(p_, C_), p_), sub(p_, D_), p_)
        C_ := addmod(D_, sub(p_, mulmod(a_, C_, p_)), p_)

        mstore(pPoint3_, mulmod(F_, mulmod(A_, H_, p_), p_))
        mstore(add(pPoint3_, 0x20), mulmod(B_, mulmod(A_, C_, p_), p_))
        mstore(add(pPoint3_, 0x40), mulmod(F_, B_, p_))
    }
}

function _add(
    CMT storage treaple,
    uint256 rootNodeId_,
    bytes32 key_
) private returns (uint256) {
    Node storage rootNode = treaple.nodes[uint64(rootNodeId_)];

    if (rootNode.key == 0) {
        return _newNode(treaple, key_);
    }

    if (rootNode.key == key_) revert KeyAlreadyExists();

    if (rootNode.key > key_) {
        rootNode.childLeft = uint64(_add(treaple, rootNode.childLeft, key_));

        if (treaple.nodes[rootNode.childLeft].priority > rootNode.priority) {
            rootNodeId_ = _rightRotate(treaple, rootNodeId_);
            rootNode = treaple.nodes[uint64(rootNodeId_)];
        }
    } else {
        rootNode.childRight = uint64(_add(treaple, rootNode.childRight, key_));

        if (treaple.nodes[rootNode.childRight].priority > rootNode.priority) {
            rootNodeId_ = _leftRotate(treaple, rootNodeId_);
            rootNode = treaple.nodes[uint64(rootNodeId_)];
        }
    }

    rootNode.merkleHash = _hashNodes(treaple, rootNodeId_);

    return rootNodeId_;
}

function _add(IMT storage tree, bytes32 element_) private {
    function(bytes32) view returns (bytes32) hash1_ = tree.isCustomHasherSet
        ? tree.hash1
        : _hash1;
    function(bytes32, bytes32) view returns (bytes32) hash2_ = tree.isCustomHasherSet
        ? tree.hash2
        : _hash2;

    bytes32 resultValue_ = hash1_(element_);

    uint256 index_ = 0;
    uint256 size_ = ++tree.leavesCount;
    uint256 treeHeight_ = tree.branches.length;

    while (index_ < treeHeight_) {
        if (size_ & 1 == 1) {
            break;
        }

        bytes32 branch_ = tree.branches[index_];
        resultValue_ = hash2_(branch_, resultValue_);

        size_ >>= 1;
        ++index_;
    }

    if (index_ == treeHeight_) {
        if (tree.isStrictHeightSet) revert TreeIsFull();

        tree.branches.push(resultValue_);
    } else {
        tree.branches[index_] = resultValue_;
    }
}

function _root(IMT storage tree) private view returns (bytes32) {
    function(bytes32) view returns (bytes32) hash1_ = tree.isCustomHasherSet
        ? tree.hash1
        : _hash1;
    function(bytes32, bytes32) view returns (bytes32) hash2_ = tree.isCustomHasherSet
        ? tree.hash2
        : _hash2;

    uint256 treeHeight_ = tree.branches.length;

    if (treeHeight_ == 0) {
        return hash1_(bytes32(0));
    }

    uint256 height_;
    uint256 size_ = tree.leavesCount;
    bytes32 root_ = hash1_(bytes32(0));
    bytes32[] memory zeroHashes_ = _getZeroHashes(tree, treeHeight_);

    while (height_ < treeHeight_) {
        if (size_ & 1 == 1) {
            bytes32 branch_ = tree.branches[height_];

            root_ = hash2_(branch_, root_);
        } else {
            bytes32 zeroHash_ = zeroHashes_[height_];

            root_ = hash2_(root_, zeroHash_);
        }

        size_ >>= 1;
        ++height_;
    }

    return root_;
}

function _pushLeaf(
    IndexedMT storage tree,
    uint256 leafIndex_,
    LeafData memory leafData_
) private {
    tree.leavesData.push(leafData_);

    uint256 levelsCount_ = tree.levelsCount;
    uint256 levelIndex_ = leafIndex_;

    HashFunctions memory hashFunctions_ = _getHashFunctions(tree);

    for (uint256 i = 0; i < levelsCount_; i++) {
        bytes32 currentLevelNodeHash_;

        if (i == LEAVES_LEVEL) {
            currentLevelNodeHash_ = _hashLeaf(
                levelIndex_,
                leafData_.value,
                leafData_.nextLeafIndex,
                true,
                hashFunctions_.hash4
            );
        } else {
            currentLevelNodeHash_ = _calculateNodeHash(tree, levelIndex_, i, hashFunctions_);
        }

        if (levelIndex_ == _getLevelNodesCount(tree, i)) {
            tree.nodes[i].push(currentLevelNodeHash_);
        } else {
            tree.nodes[i][levelIndex_] = currentLevelNodeHash_;
        }

        if (i + 1 == levelsCount_ && _getLevelNodesCount(tree, i) > 1) {
            levelsCount_++;
        }

        levelIndex_ /= 2;
    }

    tree.levelsCount = levelsCount_;
}

function _proof(
    IndexedMT storage tree,
    uint256 index_,
    bytes32 value_
) private view returns (Proof memory) {
    LeafData memory leafData_ = _getLeafData(tree, index_);

    Proof memory proof_ = Proof({
        root: _getRoot(tree),
        siblings: new bytes32[](tree.levelsCount - 1),
        existence: false,
        index: index_,
        value: leafData_.value,
        nextLeafIndex: leafData_.nextLeafIndex
    });

    if (leafData_.value == value_) {
        proof_.existence = true;
    } else if (!_isLowLeaf(tree, value_, index_)) {
        revert InvalidProofIndex(index_, value_);
    }

    HashFunctions memory hashFunctions_ = _getHashFunctions(tree);

    uint256 parentIndex_ = index_;

    for (uint256 i = 0; i < proof_.siblings.length; ++i) {
        uint256 currentLevelIndex_ = parentIndex_ % 2 == 0
            ? parentIndex_ + 1
            : parentIndex_ - 1;

        proof_.siblings[i] = currentLevelIndex_ < _getLevelNodesCount(tree, i)
            ? tree.nodes[i][currentLevelIndex_]
            : _getZeroNodeHash(i, hashFunctions_);

        parentIndex_ /= 2;
    }

    return proof_;
}

function _add(
    SMT storage tree,
    Node memory newLeaf_,
    uint256 nodeId_,
    uint16 currentDepth_
) private returns (uint256) {
    Node memory currentNode_ = tree.nodes[nodeId_];

    if (currentNode_.nodeType == NodeType.EMPTY) {
        return _setNode(tree, newLeaf_);
    } else if (currentNode_.nodeType == NodeType.LEAF) {
        if (currentNode_.key == newLeaf_.key) revert KeyAlreadyExists(newLeaf_.key);

        return _pushLeaf(tree, newLeaf_, currentNode_, nodeId_, currentDepth_);
    } else {
        uint256 nextNodeId_;

        if ((uint256(newLeaf_.key) >> currentDepth_) & 1 == 1) {
            nextNodeId_ = _add(tree, newLeaf_, currentNode_.childRight, currentDepth_ + 1);

            tree.nodes[nodeId_].childRight = uint64(nextNodeId_);
        } else {
            nextNodeId_ = _add(tree, newLeaf_, currentNode_.childLeft, currentDepth_ + 1);

            tree.nodes[nodeId_].childLeft = uint64(nextNodeId_);
        }

        tree.nodes[nodeId_].nodeHash = _getNodeHash(tree, tree.nodes[nodeId_]);

        return nodeId_;
    }
}

function _processProof(
    function(bytes32, bytes32) view returns (bytes32) hash2_,
    function(bytes32, bytes32, bytes32) view returns (bytes32) hash3_,
    Proof memory proof_
) private view returns (bytes32) {
    bytes32 computedHash_;

    if (proof_.existence) {
        computedHash_ = hash3_(proof_.key, proof_.value, bytes32(uint256(1)));
    } else if (proof_.auxExistence) {
        computedHash_ = hash3_(proof_.auxKey, proof_.auxValue, bytes32(uint256(1)));
    } else {
        computedHash_ = bytes32(0);
    }

    uint256 pathIndex_ = uint256(proof_.key);
    uint256 depth_ = proof_.siblings.length;

    while (depth_ > 0 && proof_.siblings[depth_ - 1] == bytes32(0)) {
        --depth_;
    }

    for (uint256 i = depth_; i > 0; --i) {
        uint256 sIndex_ = i - 1;

        if ((pathIndex_ >> sIndex_) & 1 == 1) {
            computedHash_ = hash2_(proof_.siblings[sIndex_], computedHash_);
        } else {
            computedHash_ = hash2_(computedHash_, proof_.siblings[sIndex_]);
        }
    }

    return computedHash_;
}

function _nodeByKey(SMT storage tree, bytes32 key_) private view returns (Node memory) {
    Node memory node_;
    uint256 nextNodeId_ = tree.merkleRootId;

    for (uint256 i = 0; i <= tree.maxDepth; ++i) {
        node_ = tree.nodes[nextNodeId_];

        if (node_.nodeType == NodeType.EMPTY) {
            break;
        } else if (node_.nodeType == NodeType.LEAF) {
            if (node_.key == key_) {
                break;
            }
        } else {
            if ((uint256(key_) >> i) & 1 == 1) {
                nextNodeId_ = node_.childRight;
            } else {
                nextNodeId_ = node_.childLeft;
            }
        }
    }

    return
        node_.key == key_
            ? node_
            : Node({
                nodeType: NodeType.EMPTY,
                childLeft: ZERO_IDX,
                childRight: ZERO_IDX,
                nodeHash: ZERO_HASH,
                key: ZERO_HASH,
                value: ZERO_HASH
            });
}

function testUintFunctionality() external pure {
    Vector.UintVector memory vector_ = Vector.newUint();

    if (vector_.length() != 0) revert();

    vector_.push(1);
    vector_.set(0, 2);
    vector_.push(2);
    vector_.set(vector_.length() - 1, 3);

    uint256[] memory array_ = vector_.toArray();

    if (array_.length != 2) revert();
    if (array_[0] != 2) revert();
    if (array_[1] != 3) revert();

    array_[0] = 10;

    if (vector_.at(0) != 10) revert();

    vector_ = Vector.newUint(5);
    array_ = vector_.toArray();

    if (array_.length != 5) revert();

    vector_.push(0);
    vector_.pop();

    array_ = vector_.toArray();

    if (array_.length != 5) revert();

    array_[array_.length - 1] = 1;
    vector_ = Vector.newUint(array_);

    if (vector_.length() != 5) revert();
    if (vector_.at(vector_.length() - 1) != 1) revert();

    vector_.push([uint256(1), 2, 3].asDynamic());

    if (vector_.length() != 8) revert();
}

function testAddressFunctionality() external pure {
    Vector.AddressVector memory vector_ = Vector.newAddress();

    if (vector_.length() != 0) revert();

    vector_.push(address(1));
    vector_.set(0, address(2));
    vector_.push(address(2));
    vector_.set(vector_.length() - 1, address(3));

    address[] memory array_ = vector_.toArray();

    if (array_.length != 2) revert();
    if (array_[0] != address(2)) revert();
    if (array_[1] != address(3)) revert();

    array_[0] = address(10);

    if (vector_.at(0) != address(10)) revert();

    vector_ = Vector.newAddress(5);
    array_ = vector_.toArray();

    if (array_.length != 5) revert();

    vector_.push(address(0));
    vector_.pop();

    array_ = vector_.toArray();

    if (array_.length != 5) revert();

    array_[array_.length - 1] = address(1);
    vector_ = Vector.newAddress(array_);

    if (vector_.length() != 5) revert();
    if (vector_.at(vector_.length() - 1) != address(1)) revert();

    vector_.push([address(5), address(4), address(3)].asDynamic());

    if (vector_.length() != 8) revert();
}

function powu(SD59x18 x, uint256 y) pure returns (SD59x18 result) {
    if (y == 0) return UNIT;
    uint256 xAbs = uint256(abs(x).unwrap());

    // Calculate the first iteration of the loop in advance.
    uint256 resultAbs = y & 1 > 0 ? xAbs : uint256(uUNIT);

    // Equivalent to `for(y /= 2; y > 0; y /= 2)`.
    uint256 yAux = y;
    for (yAux >>= 1; yAux > 0; yAux >>= 1) {
        xAbs = Common.mulDiv18(xAbs, xAbs);

        // Equivalent to `y % 2 == 1`.
        if (yAux & 1 > 0) {
            resultAbs = Common.mulDiv18(resultAbs, xAbs);
        }
    }

    // The result must fit in SD59x18.
    if (resultAbs > uint256(uMAX_SD59x18)) {
        revert Errors.PRBMath_SD59x18_Powu_Overflow(x, y);
    }

    unchecked {
        // Is the base negative and the exponent odd? If yes, the result should be negative.
        int256 resultInt = int256(resultAbs);
        bool isNegative = x.unwrap() < 0 && y & 1 == 1;
        if (isNegative) {
            resultInt = -resultInt;
        }
        result = wrap(resultInt);
    }
}

function pow(UD60x18 x, UD60x18 y) pure returns (UD60x18 result) {
    uint256 xUint = x.unwrap();
    uint256 yUint = y.unwrap();

    // If both x and y are zero, the result is `UNIT`. If just x is zero, the result is always zero.
    if (xUint == 0) {
        return yUint == 0 ? UNIT : ZERO;
    }
    // If x is `UNIT`, the result is always `UNIT`.
    else if (xUint == uUNIT) {
        return UNIT;
    }

    // If y is zero, the result is always `UNIT`.
    if (yUint == 0) {
        return UNIT;
    }
    // If y is `UNIT`, the result is always x.
    else if (yUint == uUNIT) {
        return x;
    }

    // If x is > UNIT, use the standard formula.
    if (xUint > uUNIT) {
        result = exp2(mul(log2(x), y));
    }
    // Conversely, if x < UNIT, use the equivalent formula.
    else {
        UD60x18 i = wrap(uUNIT_SQUARED / xUint);
        UD60x18 w = exp2(mul(log2(i), y));
        result = wrap(uUNIT_SQUARED / w.unwrap());
    }
}
